// ─── HELPER: extract YT ID from full URL ──────────────────────────────────────
function yt(url) {
  if (!url) return null;
  const m = url.match(/(?:v=|youtu\.be\/)([^&?#]{11})/);
  return m ? m[1] : url; // if already an ID, return as-is
}

